/**
 * Adapter: API RevenueSeriesResult → existing ComparisonMetric shape
 * the hand-built chart consumes.
 *
 * The API returns 12 monthly buckets per period; the chart wants
 * `prior: number[12]`, `current: number[12]`, plus presentation
 * metadata (yMin/yMax/yAxis/format/kicker/etc.). Per-metric metadata
 * is fixed (label, formatter, line vs bar); the rest is derived from
 * the actual values so the y-axis tracks live data.
 *
 * Null bucket values become 0 — the chart can't render gaps, and the
 * API uses null only for "no orders that month" which is functionally
 * the same as zero for the comparison view.
 */

import type { ComparisonMetric } from "./data-data";
import type { RevenueSeriesResult, SeriesMetric, SeriesPoint } from "../types/api";

interface MetricMeta {
  switchLabel: string;
  kicker: string;
  type: "line" | "bars";
  /** Returns a formatter that accepts the raw API value and emits the chart's label. */
  format: (v: number) => string;
  /** For axis labels — converts a bucket value to a short string. */
  axisLabel: (v: number) => string;
}

const META: Record<SeriesMetric, MetricMeta> = {
  revenue: {
    switchLabel: "Revenue",
    kicker: "Net Revenue · 12-month rolling",
    type: "line",
    format: (v) => formatCurrencyCompact(v),
    axisLabel: (v) => formatCurrencyCompact(v),
  },
  orders: {
    switchLabel: "Orders",
    kicker: "Orders · monthly count",
    type: "bars",
    format: (v) => Math.round(v).toLocaleString(),
    axisLabel: (v) => Math.round(v).toLocaleString(),
  },
  profit: {
    switchLabel: "Profit",
    kicker: "Net Profit · 12-month rolling",
    type: "line",
    format: (v) => formatCurrencyCompact(v),
    axisLabel: (v) => formatCurrencyCompact(v),
  },
  aov: {
    switchLabel: "AOV",
    kicker: "Average Order Value · 12-month rolling",
    type: "line",
    format: (v) => formatCurrencyCompact(v),
    axisLabel: (v) => formatCurrencyCompact(v),
  },
  ltv: {
    switchLabel: "LTV",
    kicker: "Customer Lifetime Value · 12-month rolling",
    type: "line",
    format: (v) => formatCurrencyCompact(v),
    axisLabel: (v) => formatCurrencyCompact(v),
  },
  refund_rate: {
    switchLabel: "Refund Rate",
    kicker: "Refund Rate · 12-month rolling",
    type: "line",
    format: (v) => `${v.toFixed(1)}%`,
    axisLabel: (v) => `${v.toFixed(1)}%`,
  },
};

export function adaptRevenueSeries(api: RevenueSeriesResult): ComparisonMetric {
  const meta = META[api.metric];
  const current = toNumbers(api.period_a);
  const prior = toNumbers(api.period_b);
  const { yMin, yMax, yAxis } = computeAxis([...current, ...prior], meta.axisLabel);

  const lastCurrent = current[current.length - 1] ?? 0;
  const lastPrior = prior[prior.length - 1] ?? 0;
  const deltaAbs = lastCurrent - lastPrior;
  const deltaPct = lastPrior === 0 ? 0 : (deltaAbs / lastPrior) * 100;

  return {
    key: api.metric,
    switchLabel: meta.switchLabel,
    type: meta.type,
    kicker: meta.kicker,
    sub: "Monthly comparison · current period overlaid on prior year",
    yMax,
    yMin,
    yAxis,
    format: meta.format,
    prior,
    current,
    varianceBufferPct: 0.06,
    annotations: api.annotations.map((a) => ({
      i: monthIndex(a.month, api.period_a),
      d: shortDate(a.month),
      t: a.label.toUpperCase(),
    })),
    periodB: meta.format(lastPrior),
    periodA: meta.format(lastCurrent),
    delta: {
      arrow: deltaAbs >= 0 ? `↑ ${meta.format(Math.abs(deltaAbs))}` : `↓ ${meta.format(Math.abs(deltaAbs))}`,
      pct: `${deltaPct >= 0 ? "+" : ""}${deltaPct.toFixed(1)}%`,
      dir: deltaAbs >= 0 ? "up" : "down",
    },
    context: "",
    rate: "",
    vol: "",
    conf: "",
  };
}

function toNumbers(points: SeriesPoint[]): number[] {
  // Chart wants exactly 12 buckets — pad with zeros if the API returns
  // fewer (newer accounts with <12 months of history).
  const arr = points.map((p) => p.value ?? 0);
  while (arr.length < 12) arr.unshift(0);
  return arr.slice(-12);
}

function computeAxis(
  values: number[],
  format: (v: number) => string,
): { yMin: number; yMax: number; yAxis: [string, string, string, string] } {
  const filtered = values.filter((v) => Number.isFinite(v));
  if (filtered.length === 0) {
    return { yMin: 0, yMax: 100, yAxis: ["100", "75", "50", "25"] };
  }
  const rawMin = Math.min(...filtered);
  const rawMax = Math.max(...filtered);
  // 8% padding above/below so the line never touches the axis.
  const pad = (rawMax - rawMin) * 0.08 || rawMax * 0.08 || 1;
  const yMin = Math.max(0, Math.floor(rawMin - pad));
  const yMax = Math.ceil(rawMax + pad);
  const step = (yMax - yMin) / 3;
  return {
    yMin,
    yMax,
    yAxis: [
      format(yMax),
      format(yMax - step),
      format(yMin + step),
      format(yMin),
    ],
  };
}

function formatCurrencyCompact(n: number): string {
  if (Math.abs(n) >= 1_000_000) return `$${(n / 1_000_000).toFixed(2)}M`;
  if (Math.abs(n) >= 1_000) return `$${(n / 1_000).toFixed(0)}K`;
  return `$${Math.round(n).toLocaleString()}`;
}

function monthIndex(month: string, periodA: SeriesPoint[]): number {
  const idx = periodA.findIndex((p) => p.month === month);
  return idx >= 0 ? idx : 0;
}

function shortDate(monthIso: string): string {
  const d = new Date(`${monthIso}T00:00:00Z`);
  const m = ["JAN", "FEB", "MAR", "APR", "MAY", "JUN", "JUL", "AUG", "SEP", "OCT", "NOV", "DEC"][
    d.getUTCMonth()
  ];
  return `${m} ${d.getUTCDate()}`;
}
