"use client";

import { useQuery } from "@tanstack/react-query";
import { fetchRevenueSeries } from "../api/data-api";
import type { RevenueSeriesQueryParams } from "../types/api";
import { dataKeys } from "./data-keys";

export function useDataRevenueSeries(params: RevenueSeriesQueryParams | null) {
  return useQuery({
    queryKey: params ? dataKeys.revenueSeries(params) : dataKeys.all,
    queryFn: () => fetchRevenueSeries(params as RevenueSeriesQueryParams),
    enabled: Boolean(params?.account_id),
  });
}
