/**
 * Adapter: API TopProductRow[] → existing ProductRow[] used by the
 * "Top products · by revenue" table.
 *
 * Display strings (formatted currency, signed delta, two-letter
 * thumbnail) are derived here so the table component stays a dumb
 * renderer of pre-baked text.
 */

import type { ProductRow } from "./data-data";
import type { TopProductRow } from "../types/api";

export function adaptTopProducts(rows: TopProductRow[]): ProductRow[] {
  return rows.map((r) => ({
    thumb: thumbFromName(r.name),
    name: r.name,
    sub: buildSub(r),
    current: formatCurrency(r.revenue),
    prior: r.prior_revenue == null ? "—" : formatCurrency(r.prior_revenue),
    delta: formatDelta(r.delta_pct),
    deltaDir: r.delta_pct != null && r.delta_pct < 0 ? "down" : "up",
  }));
}

function thumbFromName(name: string): string {
  // First letter of each of the first two words; pad to two chars.
  const parts = name.trim().split(/\s+/).slice(0, 2);
  const letters = parts.map((p) => p[0]?.toUpperCase() ?? "").join("");
  return (letters || name.slice(0, 2).toUpperCase()).slice(0, 2);
}

function buildSub(r: TopProductRow): string {
  const segments: string[] = [];
  if (r.sku) segments.push(r.sku);
  if (r.category) segments.push(r.category);
  segments.push(`${r.units_sold.toLocaleString()} sold`);
  return segments.join(" · ");
}

function formatCurrency(n: number): string {
  return `$${Math.round(n).toLocaleString()}`;
}

function formatDelta(pct: number | null): string {
  if (pct == null) return "—";
  const sign = pct >= 0 ? "+" : "−";
  return `${sign}${Math.abs(pct).toFixed(1)}%`;
}
