"use client";

import { useQuery } from "@tanstack/react-query";
import { fetchKpis } from "../api/data-api";
import type { DataQueryParams } from "../types/api";
import { dataKeys } from "./data-keys";

/**
 * Fetches /data/kpis. `enabled` is gated on a non-empty account_id so
 * the hook doesn't fire until the caller knows which account to scope.
 */
export function useDataKpis(params: DataQueryParams | null) {
  return useQuery({
    queryKey: params ? dataKeys.kpis(params) : dataKeys.all,
    queryFn: () => fetchKpis(params as DataQueryParams),
    enabled: Boolean(params?.account_id),
  });
}
