/* ───────────────────────── Page ───────────────────────── */

type Popover = "none" | "calendar-a" | "calendar-b" | "mode";
interface PeriodOverride { value: string; days: number; }

// Hardcoded comparison window for the first wired endpoint. The period
// picker UI lives below but isn't yet plumbed back into ISO dates; this
// matches the mock copy ("May 2026 vs May 2025"). Wire the picker to
// real dates when other endpoints come online.
const PERIOD_QUERY = {
  period_a_start: "2026-05-01",
  period_a_end: "2026-05-19",
  period_b_start: "2025-05-01",
  period_b_end: "2025-05-19",
} as const;

export default function DataPage() {
  const me = useMe();
  const accountId = me.data?.accounts[0]?.id;
  const baseParams = accountId ? { account_id: accountId, ...PERIOD_QUERY } : null;

  const kpisQuery = useDataKpis(baseParams);
  const countsQuery = useDataCounts(baseParams);
  const topProductsQuery = useDataTopProducts(baseParams ? { ...baseParams, limit: 5 } : null);
  const insightsQuery = useDataInsights(baseParams);

  const [metricKey, setMetricKey] = useState<string>("revenue");
  const apiMetric = SUPPORTED_METRICS[metricKey];
  // Anchor at the end of period A so the trailing-12-month window lines
  // up with the comparison the rest of the page is showing.
  const revenueSeriesQuery = useDataRevenueSeries(
    accountId && apiMetric
      ? { account_id: accountId, metric: apiMetric, anchor: PERIOD_QUERY.period_a_end }
      : null,
  );

  // Fall back to the mock shapes until live responses arrive so layouts
  // never collapse mid-load.
  const kpiCells = useMemo(
    () => (kpisQuery.data ? adaptKpis(kpisQuery.data) : data.kpis),
    [kpisQuery.data],
  );
  const entityCards = useMemo(
    () => (countsQuery.data ? adaptCounts(countsQuery.data) : data.entities),
    [countsQuery.data],
  );
  const topProductRows = useMemo(
    () => (topProductsQuery.data ? adaptTopProducts(topProductsQuery.data) : data.topProducts),
    [topProductsQuery.data],
  );
  const insightCards = useMemo(
    () => (insightsQuery.data ? adaptInsights(insightsQuery.data) : data.ai.cards),
    [insightsQuery.data],
  );
  const liveMetric = useMemo(
    () => (revenueSeriesQuery.data ? adaptRevenueSeries(revenueSeriesQuery.data) : null),
    [revenueSeriesQuery.data],
  );
  const [modeKey, setModeKey] = useState<string>("yoy");
  const [popover, setPopover] = useState<Popover>("none");
  const [moreOpen, setMoreOpen] = useState(false);
  const [addFilterOpen, setAddFilterOpen] = useState(false);
  // The Active filters bar is the source of truth; a quick slice is "active"
  // when all of its underlying filters are currently applied.
  const [filters, setFilters] = useState<{ dim: string; value: string }[]>(data.activeFilters);
  const sliceActive = (sl: (typeof data.quickSlices)[number]) =>
    sl.filters.every((sf) => filters.some((f) => f.dim === sf.dim && f.value === sf.value));
  const toggleSlice = (sl: (typeof data.quickSlices)[number]) => {
    setFilters((cur) => {
      const isActive = sl.filters.every((sf) => cur.some((f) => f.dim === sf.dim && f.value === sf.value));
      if (isActive) {
        // Tapping again clears the slice's filters.
        return cur.filter((f) => !sl.filters.some((sf) => sf.dim === f.dim && sf.value === f.value));
      }
      // Apply: upsert each filter (replace any existing pill on the same dimension).
      let next = cur;
      for (const sf of sl.filters) {
        next = [...next.filter((f) => f.dim !== sf.dim), sf];
      }
      return next;
    });
  };
  const mode0 = data.modes.find((m) => m.mode === "yoy") ?? data.modes[0];
  // Each period is { value (pill label), days }. metaMode "preset" shows the
  // active comparison mode's meta; "computed" shows the honest day-match line
  // (set the moment a period is edited on the calendar — live, not on Apply).
  const [periodA, setPeriodA] = useState<PeriodOverride>({ value: data.periodA.value, days: mode0.aDays });
  const [periodB, setPeriodB] = useState<PeriodOverride>({ value: data.periodB.value, days: mode0.bDays });
  const [metaMode, setMetaMode] = useState<"preset" | "computed">("preset");

  // Live metric (from /data/revenue-series) wins when available;
  // otherwise fall back to the mock entry for that metric key so the
  // chart renders something while we wait — and so unsupported
  // diagnostic metrics (e.g. "bounce") keep working.
  const mockMetric = data.metrics.find((m) => m.key === metricKey) ?? data.metrics[0];
  const metric = liveMetric ?? mockMetric;
  const mode = data.modes.find((m) => m.mode === modeKey) ?? data.modes[0];
  const primaryMetrics = data.metrics.filter((m) => !m.diagnostic);
  const diagnosticMetrics = data.metrics.filter((m) => m.diagnostic);

  const periodAValue = periodA.value;
  const periodBValue = periodB.value;
  const aDays = periodA.days;
  const bDays = periodB.days;
  // Day-match honesty: equal → neutral "1:1 day match"; different → amber
  // "not comparable". Only once a period is hand-edited (metaMode "computed");
  // comparison modes keep their own intentional meta label.
  const mismatch = metaMode === "computed" && aDays !== bDays;
  const dayLbl = (n: number) => `${n} ${n === 1 ? "day" : "days"}`;
  const metaHtml =
    metaMode === "preset"
      ? mode.meta
      : mismatch
        ? `${dayLbl(aDays)} vs ${dayLbl(bDays)} · <b>not comparable</b> — match lengths for a valid comparison`
        : `${dayLbl(aDays)} · ${dayLbl(bDays)} · <b>1:1 day match</b>`;
  // Editing a period live (calendar) → switch to the computed honest meta.
  const applyPeriod = (ctx: "a" | "b", p: PeriodOverride) => {
    if (ctx === "a") setPeriodA(p);
    else setPeriodB(p);
    setMetaMode("computed");
  };
  const activeDiagnostic = diagnosticMetrics.find((m) => m.key === metricKey);

  // Close all popovers / dropdowns on any outside click.
  useEffect(() => {
    const onDoc = (e: MouseEvent) => {
      // Keep popovers open when the click is inside a popover region or its
      // trigger; only true outside clicks dismiss them. (React's event
      // delegation sits on the same node as this listener, so stopPropagation
      // alone can't prevent it — hence the explicit target guard.)
      if ((e.target as HTMLElement | null)?.closest?.(".period-stack, .filter-card, .metric-switcher")) return;
      setPopover("none");
      setMoreOpen(false);
      setAddFilterOpen(false);
    };
    document.addEventListener("click", onDoc);
    return () => document.removeEventListener("click", onDoc);
  }, []);

  const stop = (e: React.MouseEvent) => e.stopPropagation();

  return (
    <div className="data-room">
      <div className="dept-wrap">
        {/* ── HEADER — title on the left, period control on the right ── */}
        <div className="dept-head">
          <div className="dept-head-top">
            <div className="dept-title-wrap">
              <DeptIcon dept="data" />
              <div>
                <div className="dept-title">Data Overview</div>
                <div className="dept-meta">
                  <span className="live">Live</span> · {data.meta}
                </div>
              </div>
            </div>

            {/* ── PERIOD PAIR (bespoke comparison control) ── */}
            <div className="period-stack" onClick={stop}>
            <div className="period-pair" role="group" aria-label="Period comparison">
              <button
                className="period-pill"
                onClick={() => setPopover((p) => (p === "calendar-b" ? "none" : "calendar-b"))}
              >
                <div className="period-pill-text">
                  <div className="kicker">{data.periodB.kicker}</div>
                  <div className="value">{periodBValue}</div>
                </div>
                <span className="chev">▾</span>
              </button>
              <button
                className="period-vs"
                aria-label="Compare mode"
                onClick={() => setPopover((p) => (p === "mode" ? "none" : "mode"))}
              >
                <span className="vs-label">vs</span>
                <span className="mode">{mode.label} <span className="chev">▾</span></span>
              </button>
              <button
                className="period-pill"
                onClick={() => setPopover((p) => (p === "calendar-a" ? "none" : "calendar-a"))}
              >
                <div className="period-pill-text">
                  <div className="kicker">{data.periodA.kicker}</div>
                  <div className="value">{periodAValue}</div>
                </div>
                <span className="chev">▾</span>
              </button>
            </div>
            <div
              className={`period-meta${mismatch ? " mismatch" : ""}`}
              dangerouslySetInnerHTML={{ __html: metaHtml }}
            />

            {/* Calendar popover */}
            {(popover === "calendar-a" || popover === "calendar-b") && (
              <CalendarPopover
                context={popover === "calendar-a" ? "a" : "b"}
                modeLabel={mode.label}
                committedA={{ value: periodAValue, days: aDays }}
                committedB={{ value: periodBValue, days: bDays }}
                onLiveChange={applyPeriod}
                onApply={(ctx, applied) => {
                  applyPeriod(ctx, applied);
                  setPopover("none");
                }}
                onClose={() => setPopover("none")}
              />
            )}

            {/* Mode picker popover */}
            {popover === "mode" && (
              <div className="popover mode-picker-popover" onClick={stop}>
                {data.modes.map((m) => (
                  <button
                    key={m.mode}
                    className={`mode-option${m.mode === modeKey ? " active" : ""}`}
                    onClick={() => {
                      // The chosen mode redefines both periods + its own meta label.
                      setModeKey(m.mode);
                      setPeriodA({ value: data.periodA.value, days: m.aDays });
                      setPeriodB({ value: m.periodB, days: m.bDays });
                      setMetaMode("preset");
                      setPopover("none");
                    }}
                  >
                    <div className="mode-option-label">
                      {m.optionLabel} <span className="check">✓</span>
                    </div>
                    <div className="mode-option-desc">{m.desc}</div>
                  </button>
                ))}
              </div>
            )}
            </div>
          </div>
        </div>

        {/* ── FILTER CARD ── */}
        <div className="filter-card">
          <div className="quick-slices">
            <span className="quick-slices-label">Quick slices</span>
            {data.quickSlices.map((s) => (
              <button
                key={s.label}
                className={`quick-slice${sliceActive(s) ? " active" : ""}`}
                title={s.intent}
                onClick={() => toggleSlice(s)}
              >
                {s.label}
              </button>
            ))}
          </div>
          <div className="filter-bar">
            <span className="filter-bar-label">Active filters</span>
            {filters.map((f) => (
              <button key={f.dim} className="filter-pill applied">
                <span className="dim-name">{f.dim} ·</span>
                <span className="value">{f.value}</span>
                <span
                  className="clear-btn"
                  onClick={(e) => {
                    e.stopPropagation();
                    setFilters((cur) => cur.filter((x) => x.dim !== f.dim));
                  }}
                >
                  ×
                </span>
              </button>
            ))}
            <button
              className="filter-pill add"
              onClick={(e) => {
                e.stopPropagation();
                setAddFilterOpen((v) => !v);
              }}
            >
              + Add filter
            </button>
            {filters.length > 0 && (
              <span className="filter-bar-clear" onClick={() => setFilters([])}>
                Clear all
              </span>
            )}

            {addFilterOpen && (
              <div className="addfilter-pop" onClick={stop}>
                <div className="afp-head">Add a filter dimension</div>
                {data.addFilterDims
                  .filter((d) => !filters.some((f) => f.dim === d.dim))
                  .map((d) => (
                    <button
                      key={d.dim}
                      className="afp-item"
                      onClick={() => {
                        setFilters((cur) => [...cur, { dim: d.dim, value: d.value }]);
                        setAddFilterOpen(false);
                      }}
                    >
                      {d.dim}
                    </button>
                  ))}
              </div>
            )}
          </div>
        </div>

        {/* ── AI STRIP (shared component) ── */}
        <AIStrip
          label={data.ai.label}
          meta={{ confidence: data.ai.confidence, sources: data.ai.sources, syncedAgo: data.ai.syncedAgo }}
          cards={insightCards.map((c) => ({
            tag: c.tag,
            title: c.title,
            body: c.body,
            accent: c.accent,
            bridgePage: data.aiBridgePage,
          }))}
        />

        {/* ── HERO: COMPARISON CHART ── */}
        <div className="hero-card">
          <div className="hero-head">
            <div className="hero-left">
              <div className="hero-kicker">{metric.kicker}</div>
              <div className="hero-title">May 2026 vs May 2025</div>
              <div className="hero-sub">{metric.sub}</div>
            </div>
            <div className="metric-switcher" onClick={stop}>
              {primaryMetrics.map((m) => (
                <button
                  key={m.key}
                  className={m.key === metricKey ? "active" : ""}
                  onClick={() => {
                    setMetricKey(m.key);
                    setMoreOpen(false);
                  }}
                >
                  {m.switchLabel}
                </button>
              ))}
              <div className="switcher-more-wrap">
                <button
                  className={`switcher-more${activeDiagnostic ? " has-active" : ""}`}
                  onClick={(e) => {
                    e.stopPropagation();
                    setMoreOpen((v) => !v);
                  }}
                >
                  {activeDiagnostic ? `${activeDiagnostic.switchLabel} ▾` : "+ More"}
                </button>
                {moreOpen && (
                  <div className="switcher-more-dropdown" onClick={stop}>
                    <div className="switcher-more-dropdown-head">Diagnostic metrics</div>
                    {diagnosticMetrics.map((m) => (
                      <button
                        key={m.key}
                        className={`switcher-more-item${m.key === metricKey ? " active" : ""}`}
                        onClick={() => {
                          setMetricKey(m.key);
                          setMoreOpen(false);
                        }}
                      >
                        {m.switchLabel}
                        {m.dropdownMeta && (
                          <span className={`meta ${m.dropdownMeta.dir}`}>{m.dropdownMeta.text}</span>
                        )}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>

          <ComparisonChart metric={metric} />

          <div className="chart-legend">
            <span className="legend-mark"><span className="ab-badge a">A</span><span className="line" />{data.chartLegend.current}</span>
            <span className="legend-mark"><span className="ab-badge b">B</span><span className="line dashed-b" />{data.chartLegend.prior}</span>
            {metric.type !== "bars" && (
              <span className="legend-mark">
                <span className="line" style={{ background: "rgba(165,168,175,0.40)", height: 8, borderRadius: 1, width: 24 }} />
                {data.chartLegend.band}
              </span>
            )}
            <span className="legend-mark">
              <span className="line" style={{ background: "#3a5285", width: 2, height: 12 }} />
              {data.chartLegend.annotation}
            </span>
          </div>

          <div className="hero-verdict">
            <div className="verdict-cell">
              <div className="kicker">{data.verdict.bKicker}</div>
              <div className="value dim">{metric.periodB}</div>
              <div className="sub">{data.verdict.bSub}</div>
            </div>
            <div className="verdict-cell">
              <div className="kicker">{data.verdict.aKicker}</div>
              <div className="value">{metric.periodA}</div>
              <div className="sub">{data.verdict.aSub}</div>
            </div>
            <div className={`verdict-delta${metric.delta.dir === "down" ? " down" : ""}${mismatch ? " muted" : ""}`}>
              <div className="arrow">{metric.delta.arrow}</div>
              <div className="pct">{metric.delta.pct}</div>
              <div className="label">{mismatch ? "not comparable" : data.verdict.deltaLabel}</div>
            </div>
          </div>

          <div className="metric-context">
            <div className="metric-context-inner">
              <span className="metric-context-tag">What&apos;s driving this</span>
              <span className="metric-context-text">{metric.context}</span>
            </div>
            <div className="metric-context-meta">
              <span>{metric.rate}</span>
              <span>{metric.vol}</span>
              <span>{metric.conf}</span>
            </div>
          </div>
        </div>

        {/* ── KPI STRIP ── */}
        <div className="kpi-strip">
          {kpiCells.map((k) => (
            <div key={k.label} className="kpi-cell">
              {k.badge && <div className={`kpi-anomaly ${k.badge.kind}`}>{k.badge.label}</div>}
              <div className="kpi-label">{k.label}</div>
              <div className="kpi-value">{k.value}</div>
              <div className="kpi-compare">
                <div className="kpi-bar-row">
                  <span className="kpi-bar-label">Now</span>
                  <div className="kpi-bar-track">
                    <div className={`kpi-bar-fill ${k.now.down ? "now-down" : "now"}`} style={{ width: `${k.now.widthPct}%` }} />
                  </div>
                  <span className="kpi-bar-value">{k.now.value}</span>
                </div>
                <div className="kpi-bar-row">
                  <span className="kpi-bar-label">Prior</span>
                  <div className="kpi-bar-track">
                    <div className="kpi-bar-fill prior" style={{ width: `${k.prior.widthPct}%` }} />
                  </div>
                  <span className="kpi-bar-value dim">{k.prior.value}</span>
                </div>
              </div>
              <div className={`kpi-foot${k.footDir === "down" ? " down" : k.footDir === "flat" ? " flat" : ""}`}>
                {k.foot} <span className="vs">YoY</span>
              </div>
            </div>
          ))}
        </div>

        {/* ── EXPLORE THE DATA ── */}
        <div className="section-divider">
          <span className="cap">Explore the data</span>
          <span className="rule" />
        </div>
        <div className="entity-grid">
          {entityCards.map((e) => {
            const inner = (
              <>
                <div className="entity-head">
                  <div className="entity-icon">{ENTITY_GLYPHS[e.glyph]}</div>
                  <span className="entity-arrow">→</span>
                </div>
                <div className="entity-name">{e.name}</div>
                <div className="entity-value">{e.value}</div>
                <div className="entity-foot">
                  <span className={`entity-delta ${e.deltaDir}`}>{e.delta}</span>
                  <span className="entity-sub">{e.sub}</span>
                </div>
              </>
            );
            return e.href ? (
              <Link key={e.name} href={e.href} className="entity-card">
                {inner}
              </Link>
            ) : (
              <button key={e.name} className="entity-card">
                {inner}
              </button>
            );
          })}
        </div>

        {/* ── TOP PRODUCTS · BY REVENUE ── */}
        <div className="section-divider">
          <span className="cap">Top products · by revenue</span>
          <span className="rule" />
          <Link className="section-link" href="/data/products">
            View all products
            <svg viewBox="0 0 24 24"><path d="M5 12h14M13 6l6 6-6 6" /></svg>
          </Link>
        </div>
        <div className="dept-table">
          <div className="dept-row head">
            <span />
            <span>Product</span>
            <span style={{ textAlign: "right" }}>May 2026</span>
            <span style={{ textAlign: "right" }}>May 2025</span>
            <span style={{ textAlign: "right" }}>Delta</span>
          </div>
          {topProductRows.map((p) => (
            <div key={p.thumb} className="dept-row">
              <span className="dept-thumb">{p.thumb}</span>
              <span className="name">
                {p.name} <span className="sub">{p.sub}</span>
              </span>
              <span className="val">{p.current}</span>
              <span className="val dim">{p.prior}</span>
              <span className={`delta${p.deltaDir === "down" ? " down" : ""}`}>{p.delta}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

/* ───────────────────────── Calendar popover ───────────────────────── */

const DOW = ["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"];
const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December",
];
const MONTH_SHORT = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
const TODAY_ISO = "2026-05-19";

/* ── date helpers ── */
const ymd = (d: Date) =>
  `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
const addDays = (d: Date, n: number) => {
  const x = new Date(d);
  x.setDate(x.getDate() + n);
  return x;
};
/** Resolve a named preset to a concrete range in the given year. null = Custom. */
function presetRange(preset: string, year: number): { start: string; end: string } | null {
  const ref = new Date(year, 4, 19); // the demo "today" — May 19 of the editing year
  const mk = (s: Date, e: Date) => ({ start: ymd(s), end: ymd(e) });
  switch (preset) {
    case "Today": return mk(ref, ref);
    case "Yesterday": { const y = addDays(ref, -1); return mk(y, y); }
    case "Last 7 days": return mk(addDays(ref, -6), ref);
    case "Last 30 days": return mk(addDays(ref, -29), ref);
    case "Last 90 days": return mk(addDays(ref, -89), ref);
    case "Month to date": return mk(new Date(year, 4, 1), ref);
    case "Last month": return mk(new Date(year, 3, 1), new Date(year, 4, 0));
    case "Year to date": return mk(new Date(year, 0, 1), ref);
    case "Last 12 months": return mk(addDays(ref, -364), ref);
    case "All time": return mk(new Date(2020, 0, 1), ref);
    default: return null;
  }
}
const dayCount = (start: string, end: string) =>
  Math.round((new Date(`${end}T00:00:00`).getTime() - new Date(`${start}T00:00:00`).getTime()) / 86400000) + 1;
function rangeLabel(start: string, end: string): string {
  const s = new Date(`${start}T00:00:00`), e = new Date(`${end}T00:00:00`);
  const sm = MONTH_SHORT[s.getMonth()], em = MONTH_SHORT[e.getMonth()];
  const sy = s.getFullYear(), ey = e.getFullYear();
  if (start === end) return `${sm} ${s.getDate()}, ${sy}`;
  if (sy === ey && s.getMonth() === e.getMonth()) return `${sm} ${s.getDate()}–${e.getDate()}, ${sy}`;
  if (sy === ey) return `${sm} ${s.getDate()} → ${em} ${e.getDate()}, ${sy}`;
  return `${sm} ${s.getDate()}, ${sy} → ${em} ${e.getDate()}, ${ey}`;
}
/** Put the range's START month on the left pane so the painted span is in view. */
const monthOf = (iso: string) => {
  const d = new Date(`${iso}T00:00:00`);
  return { y: d.getFullYear(), m: d.getMonth() };
};

type Committed = { value: string; days: number };

function CalendarPopover({
  context,
  modeLabel,
  committedA,
  committedB,
  onLiveChange,
  onApply,
  onClose,
}: {
  context: "a" | "b";
  modeLabel: string;
  committedA: Committed;
  committedB: Committed;
  onLiveChange: (ctx: "a" | "b", applied: PeriodOverride) => void;
  onApply: (ctx: "a" | "b", applied: PeriodOverride) => void;
  onClose: () => void;
}) {
  const stop = (e: React.MouseEvent) => e.stopPropagation();
  // Period A defaults to the current year, Period B to the prior year.
  const initYear = context === "a" ? "2026" : "2025";
  const initPreset = data.calendar.activePreset;
  const initRange = presetRange(initPreset, Number(initYear));
  const [year, setYear] = useState<string>(initYear);
  const [activePreset, setActivePreset] = useState<string>(initPreset);
  const [selStart, setSelStart] = useState<string | null>(initRange?.start ?? null);
  const [selEnd, setSelEnd] = useState<string | null>(initRange?.end ?? null);
  const [calLeft, setCalLeft] = useState<{ y: number; m: number }>(
    initRange ? monthOf(initRange.start) : { y: Number(initYear), m: 3 },
  );

  const isoOf = (y: number, m: number, d: number) =>
    `${y}-${String(m + 1).padStart(2, "0")}-${String(d).padStart(2, "0")}`;

  // Push the current selection up to the period control LIVE (label + day-match
  // meta update the moment you pick — never wait for Apply).
  const pushLive = (start: string, end: string | null, presetName: string) => {
    const b = end ?? start;
    const value = presetName && presetName !== "Custom range" ? `${presetName} · ${rangeLabel(start, b)}` : rangeLabel(start, b);
    onLiveChange(context, { value, days: dayCount(start, b) });
  };

  const pickDay = (iso: string) => {
    let ns: string, ne: string | null;
    if (!selStart || (selStart && selEnd)) {
      ns = iso; ne = null; // 1st click (or reset after a full range) = new start
    } else if (iso < selStart) {
      ns = iso; ne = selStart; // 2nd click earlier than start → auto-sort
    } else {
      ns = selStart; ne = iso; // 2nd click = end
    }
    setSelStart(ns);
    setSelEnd(ne);
    setActivePreset("Custom range");
    pushLive(ns, ne, "Custom range");
  };

  // Pick a named preset → paint the range, jump the grid to its START, push live.
  const selectPreset = (p: string) => {
    setActivePreset(p);
    const r = presetRange(p, Number(year));
    if (r) {
      setSelStart(r.start);
      setSelEnd(r.end);
      setCalLeft(monthOf(r.start));
      pushLive(r.start, r.end, p);
    }
  };

  // Pick a year → navigate the grid there and re-resolve the active preset.
  const selectYear = (y: string) => {
    setYear(y);
    const r = presetRange(activePreset, Number(y));
    if (r) {
      setSelStart(r.start);
      setSelEnd(r.end);
      setCalLeft(monthOf(r.start));
      pushLive(r.start, r.end, activePreset);
    } else {
      setCalLeft({ y: Number(y), m: 3 });
    }
  };

  // Live range for the period currently being edited (in-popover footer).
  const liveDays = selStart ? (selEnd ? dayCount(selStart, selEnd) : 1) : 0;
  const liveRange = selStart ? rangeLabel(selStart, selEnd ?? selStart) : "Select a range";

  const applySelection = () => {
    if (!selStart) { onClose(); return; }
    const end = selEnd ?? selStart;
    onApply(context, { value: rangeLabel(selStart, end), days: dayCount(selStart, end) });
  };

  const renderMonth = (y: number, m: number) => {
    const first = new Date(y, m, 1).getDay();
    const days = new Date(y, m + 1, 0).getDate();
    const prevDays = new Date(y, m, 0).getDate();
    const cells: React.ReactNode[] = [];
    for (let i = first - 1; i >= 0; i--) {
      cells.push(<div key={`p${i}`} className="calendar-day disabled">{prevDays - i}</div>);
    }
    for (let d = 1; d <= days; d++) {
      const iso = isoOf(y, m, d);
      let cls = "";
      if (selStart && selEnd) {
        if (iso === selStart && iso === selEnd) cls = "range-start range-end";
        else if (iso === selStart) cls = "range-start";
        else if (iso === selEnd) cls = "range-end";
        else if (iso > selStart && iso < selEnd) cls = "in-range";
      } else if (selStart && iso === selStart) {
        cls = "range-start range-end";
      }
      if (iso === TODAY_ISO) cls += " today";
      cells.push(
        <div
          key={iso}
          className={`calendar-day ${cls}`}
          onClick={(e) => {
            e.stopPropagation();
            pickDay(iso);
          }}
        >
          {d}
        </div>,
      );
    }
    const total = first + days;
    const trail = (7 - (total % 7)) % 7;
    for (let d = 1; d <= trail; d++) {
      cells.push(<div key={`t${d}`} className="calendar-day disabled">{d}</div>);
    }
    return (
      <div className="calendar-grid">
        {DOW.map((d) => <div key={d} className="calendar-dow">{d}</div>)}
        {cells}
      </div>
    );
  };

  const rightMonth = calLeft.m === 11 ? { y: calLeft.y + 1, m: 0 } : { y: calLeft.y, m: calLeft.m + 1 };

  return (
    <div className="popover calendar-popover" onClick={stop}>
      <div className="calendar-head">
        <div className="calendar-head-title">
          Editing <b>{context === "a" ? "Period A · Current" : "Period B · Comparison"}</b>
        </div>
        <button className="calendar-close-x" onClick={onClose}>Close ×</button>
      </div>

      <div className="calendar-year-strip">
        <span className="calendar-year-strip-label">Year</span>
        {data.calendar.years.map((y) => {
          let marker = "";
          if (context === "a") {
            if (y.year === "2025") marker = " period-b-marker";
          } else if (y.year === "2026") {
            marker = " period-a-marker";
          }
          return (
            <button
              key={y.year}
              className={`calendar-year-chip${year === y.year ? " active" : ""}${marker}`}
              onClick={() => selectYear(y.year)}
            >
              <span className="year">{y.year}</span>
              <span className="total">{y.total}</span>
            </button>
          );
        })}
      </div>

      <div className="calendar-body">
        <div className="calendar-presets">
          {context === "b" && (
            <button
              className="calendar-match-action"
              onClick={() => onApply("b", { value: committedB.value, days: committedA.days })}
            >
              <span className="icon">↻</span>
              <span className="label">Match Period A&apos;s range</span>
              <span className="meta">{modeLabel}</span>
            </button>
          )}
          <div className="calendar-presets-label">Date range</div>
          {data.calendar.presets.map((p) =>
            p === "Custom range" ? (
              <span key={p}>
                <span className="calendar-preset-divider" />
                <button
                  className={`calendar-preset${activePreset === p ? " active" : ""}`}
                  onClick={() => selectPreset(p)}
                >
                  {p}
                </button>
              </span>
            ) : (
              <button
                key={p}
                className={`calendar-preset${activePreset === p ? " active" : ""}`}
                onClick={() => selectPreset(p)}
              >
                {p}
              </button>
            ),
          )}
        </div>
        <div className="calendar-months">
          <div className="calendar-month">
            <div className="calendar-month-head">
              <button
                className="calendar-month-nav"
                onClick={() =>
                  setCalLeft((c) => (c.m === 0 ? { y: c.y - 1, m: 11 } : { y: c.y, m: c.m - 1 }))
                }
              >
                ‹
              </button>
              <span className="calendar-month-title">{MONTH_NAMES[calLeft.m]} {calLeft.y}</span>
              <button className="calendar-month-nav spacer">›</button>
            </div>
            {renderMonth(calLeft.y, calLeft.m)}
          </div>
          <div className="calendar-month">
            <div className="calendar-month-head">
              <button className="calendar-month-nav spacer">‹</button>
              <span className="calendar-month-title">{MONTH_NAMES[rightMonth.m]} {rightMonth.y}</span>
              <button
                className="calendar-month-nav"
                onClick={() =>
                  setCalLeft((c) => (c.m === 11 ? { y: c.y + 1, m: 0 } : { y: c.y, m: c.m + 1 }))
                }
              >
                ›
              </button>
            </div>
            {renderMonth(rightMonth.y, rightMonth.m)}
          </div>
        </div>
      </div>

      <div className="calendar-footer">
        <div className="calendar-periods-display">
          <div className={`calendar-period-line${context === "a" ? " active" : ""}`}>
            <span className="kicker">Period A</span>
            <span className="range">{context === "a" ? liveRange : committedA.value}</span>
            <span className="days">{context === "a" ? liveDays : committedA.days} days</span>
          </div>
          <div className={`calendar-period-line${context === "b" ? " active" : ""}`}>
            <span className="kicker">Period B</span>
            <span className="range">{context === "b" ? liveRange : committedB.value}</span>
            <span className="days">{context === "b" ? liveDays : committedB.days} days</span>
          </div>
        </div>
        <div className="calendar-footer-actions">
          <button className="btn-cal cancel" onClick={onClose}>Cancel</button>
          <button className="btn-cal apply" onClick={applySelection}>Apply</button>
        </div>
      </div>
    </div>
  );
}
