/**
 * Adapter: API KpisResult → existing KpiCell[] used by the kpi-strip.
 *
 * The API returns numbers + status enums. The UI strip's `KpiCell`
 * shape is presentation-ready: display strings, bar widths (0–100), a
 * footer delta, optional anomaly badge. This module is the single
 * place that bridges the two — keeps formatting concerns out of the
 * component and the wire shape out of the rendering layer.
 *
 * Per-metric formatters drive label, decimals, and unit suffix (% vs
 * pp vs absolute). The bar width compares "now" to "prior" so both
 * bars share a scale; when prior is zero or null we fall back to "now
 * = 100%, prior = 0%".
 */

import type { KpiCell } from "./data-data";
import type { KpiCard, KpisKey, KpisResult } from "../types/api";

interface MetricFormatter {
  label: string;
  /** "rate" metrics use percentage-point delta + % display. */
  type: "currency" | "percent" | "ratio";
  /** Compact display variant (e.g. "$412.8K") for the bar value. */
  compact?: (n: number) => string;
}

const METRICS: Record<KpisKey, MetricFormatter> = {
  net_profit: { label: "Net Profit", type: "currency", compact: compactCurrency },
  conversion_rate: { label: "Conversion Rate", type: "percent" },
  aov: { label: "Avg Order Value", type: "currency" },
  ltv: { label: "Customer LTV", type: "currency" },
  profit_margin: { label: "Profit Margin", type: "percent" },
  repeat_rate: { label: "Repeat Rate", type: "percent" },
  cart_recovery_rate: { label: "Cart Recovery Rate", type: "percent" },
  refund_rate: { label: "Refund Rate", type: "percent" },
};

// Order matches the source mock so the strip's slot ordering is unchanged.
const ORDER: KpisKey[] = [
  "net_profit",
  "conversion_rate",
  "aov",
  "ltv",
  "profit_margin",
  "repeat_rate",
  "cart_recovery_rate",
  "refund_rate",
];

export function adaptKpis(api: KpisResult): KpiCell[] {
  return ORDER.map((key) => buildCell(key, api[key]));
}

function buildCell(key: KpisKey, card: KpiCard): KpiCell {
  const meta = METRICS[key];
  const value = card.value ?? 0;
  const prior = card.prior_value ?? 0;

  const max = Math.max(value, prior);
  const nowPct = max === 0 ? 0 : Math.round((value / max) * 100);
  const priorPct = max === 0 ? 0 : Math.round((prior / max) * 100);

  const formatted = format(value, meta);
  const nowCompact = (meta.compact ?? ((n) => format(n, meta)))(value);
  const priorCompact = (meta.compact ?? ((n) => format(n, meta)))(prior);

  const footDir: KpiCell["footDir"] = card.delta_pct == null
    ? "flat"
    : card.delta_pct > 0
      ? "up"
      : card.delta_pct < 0
        ? "down"
        : "flat";

  // For "lower is better" metrics, an up delta is bad. The status field
  // already encodes severity; we use it to flip the foot color rather
  // than re-deriving direction-from-metric here.
  const presentationDir: KpiCell["footDir"] =
    card.status === "watch" || card.status === "anomaly"
      ? footDir === "up"
        ? "down" // anomalous lift on a "lower is better" metric paints red
        : footDir
      : footDir;

  const cell: KpiCell = {
    label: meta.label,
    value: formatted,
    now: { value: nowCompact, widthPct: nowPct },
    prior: { value: priorCompact, widthPct: priorPct },
    foot: formatFoot(card, meta),
    footDir: presentationDir,
  };
  if (card.status === "anomaly") cell.badge = { label: "Anomaly", kind: "anomaly" };
  else if (card.status === "watch") cell.badge = { label: "Watch", kind: "watch" };
  return cell;
}

function format(n: number, meta: MetricFormatter): string {
  if (meta.type === "currency") return `$${Math.round(n).toLocaleString()}`;
  if (meta.type === "percent") return `${n.toFixed(1)}%`;
  return n.toLocaleString();
}

function compactCurrency(n: number): string {
  if (Math.abs(n) >= 1_000_000) return `$${(n / 1_000_000).toFixed(1)}M`;
  if (Math.abs(n) >= 1_000) return `$${(n / 1_000).toFixed(1)}K`;
  return `$${Math.round(n).toLocaleString()}`;
}

function formatFoot(card: KpiCard, meta: MetricFormatter): string {
  if (card.delta_pct == null) return "—";
  const arrow = card.delta_pct > 0 ? "↑" : card.delta_pct < 0 ? "↓" : "→";
  // Percent-style metrics show a percentage-point delta (delta_abs);
  // currency/ratio metrics show a percent change.
  if (meta.type === "percent" && card.delta_abs != null) {
    return `${arrow} ${Math.abs(card.delta_abs).toFixed(1)}pp`;
  }
  return `${arrow} ${Math.abs(card.delta_pct).toFixed(1)}%`;
}
