"use client";

import { useQuery } from "@tanstack/react-query";
import { fetchInsights } from "../api/data-api";
import type { DataQueryParams } from "../types/api";
import { dataKeys } from "./data-keys";

export function useDataInsights(params: DataQueryParams | null) {
  return useQuery({
    queryKey: params ? dataKeys.insights(params) : dataKeys.all,
    queryFn: () => fetchInsights(params as DataQueryParams),
    enabled: Boolean(params?.account_id),
  });
}
