/**
 * Adapter: API Insight[] → existing DataAICard[] used by the AI strip.
 *
 * The API returns structured movers (key, direction, delta, current,
 * prior, confidence); the AI strip renders human-readable cards with a
 * tag chip + title + body. This module is the single place we phrase
 * those structured numbers into prose — keeps the strip dumb and the
 * insights service free of presentation concerns.
 */

import type { DataAICard } from "./data-data";
import type { Insight, InsightDirection } from "../types/api";

const TAG: Record<InsightDirection, string> = {
  lift: "OPPORTUNITY",
  decline: "RISK",
  anomaly: "ANOMALY",
};

const ACCENT: Record<InsightDirection, string> = {
  lift: "#2a4070",
  decline: "#b88a2a",
  anomaly: "#a04030",
};

export function adaptInsights(insights: Insight[]): DataAICard[] {
  return insights.map((i) => ({
    tag: TAG[i.direction],
    title: i.label,
    body: phraseBody(i),
    accent: ACCENT[i.direction],
  }));
}

function phraseBody(i: Insight): string {
  const arrow = i.direction === "decline" ? "down" : "up";
  const pct = Math.abs(i.delta_pct).toFixed(1);
  const cur = formatValue(i.key, i.current);
  const prior = formatValue(i.key, i.prior);
  const conf = i.confidence === "high" ? "high confidence" : "moderate confidence";
  return `${i.label} is ${arrow} ${pct}% (${cur} vs ${prior}) — ${conf}.`;
}

function formatValue(key: string, n: number): string {
  if (key.endsWith("_rate") || key === "conversion_rate" || key === "profit_margin") {
    return `${n.toFixed(1)}%`;
  }
  // Money-typed metrics: net_profit, aov, ltv. Default to currency.
  return `$${Math.round(n).toLocaleString()}`;
}
