"use client";

import { useQuery } from "@tanstack/react-query";
import { fetchTopProducts } from "../api/data-api";
import type { TopProductsQueryParams } from "../types/api";
import { dataKeys } from "./data-keys";

export function useDataTopProducts(params: TopProductsQueryParams | null) {
  return useQuery({
    queryKey: params ? dataKeys.topProducts(params) : dataKeys.all,
    queryFn: () => fetchTopProducts(params as TopProductsQueryParams),
    enabled: Boolean(params?.account_id),
  });
}
