/**
 * Thin fetchers for the /data/* endpoints.
 *
 * Hits the same-origin Next proxy (`/api/proxy/*`) so the browser never
 * needs the API URL or the access token in JS. Unwraps the CF success
 * envelope before returning so call sites work with the inner shape.
 */

import type {
  CountsResult,
  DataQueryParams,
  ErrorEnvelope,
  Insight,
  KpisResult,
  RevenueSeriesQueryParams,
  RevenueSeriesResult,
  SuccessEnvelope,
  TopProductRow,
  TopProductsQueryParams,
} from "../types/api";

const PROXY_BASE = "/api/proxy";

function buildBaseSearch(params: DataQueryParams): URLSearchParams {
  const sp = new URLSearchParams();
  sp.set("account_id", params.account_id);
  sp.set("period_a_start", params.period_a_start);
  sp.set("period_a_end", params.period_a_end);
  if (params.workspace_id) sp.set("workspace_id", params.workspace_id);
  if (params.period_b_start) sp.set("period_b_start", params.period_b_start);
  if (params.period_b_end) sp.set("period_b_end", params.period_b_end);
  if (params.channel) sp.set("channel", params.channel);
  if (params.customer_type) sp.set("customer_type", params.customer_type);
  return sp;
}

function buildRevenueSearch(params: RevenueSeriesQueryParams): string {
  const sp = new URLSearchParams();
  sp.set("account_id", params.account_id);
  if (params.workspace_id) sp.set("workspace_id", params.workspace_id);
  if (params.anchor) sp.set("anchor", params.anchor);
  if (params.metric) sp.set("metric", params.metric);
  if (params.channel) sp.set("channel", params.channel);
  if (params.customer_type) sp.set("customer_type", params.customer_type);
  return sp.toString();
}

async function getJson<T>(path: string): Promise<T> {
  const res = await fetch(`${PROXY_BASE}/${path}`, {
    headers: { accept: "application/json" },
    cache: "no-store",
  });
  const body = (await res.json()) as SuccessEnvelope<T> | ErrorEnvelope;
  if (!res.ok || !body.ok) {
    const msg = !body.ok ? body.error?.message : `request_failed_${res.status}`;
    throw new Error(msg ?? "request_failed");
  }
  return body.data;
}

export function fetchKpis(params: DataQueryParams): Promise<KpisResult> {
  return getJson<KpisResult>(`data/kpis?${buildBaseSearch(params).toString()}`);
}

export function fetchCounts(params: DataQueryParams): Promise<CountsResult> {
  return getJson<CountsResult>(`data/counts?${buildBaseSearch(params).toString()}`);
}

export function fetchTopProducts(params: TopProductsQueryParams): Promise<TopProductRow[]> {
  const sp = buildBaseSearch(params);
  if (params.limit != null) sp.set("limit", String(params.limit));
  return getJson<TopProductRow[]>(`data/top-products?${sp.toString()}`);
}

export function fetchInsights(params: DataQueryParams): Promise<Insight[]> {
  return getJson<Insight[]>(`data/insights?${buildBaseSearch(params).toString()}`);
}

export function fetchRevenueSeries(params: RevenueSeriesQueryParams): Promise<RevenueSeriesResult> {
  return getJson<RevenueSeriesResult>(`data/revenue-series?${buildRevenueSearch(params)}`);
}
