/**
 * Adapter: API CountsResult → existing EntityCard[] used by the
 * Explore-the-data grid.
 *
 * Order + glyph + href are fixed (UI navigation contract); value /
 * delta / sub are derived from the API's CountTile + its optional
 * `note` (the service already computes things like "9 abandoned" or
 * "3 below reorder" — we surface them as-is so the data layer stays
 * in charge of business labels).
 */

import type { EntityCard, EntityGlyph } from "./data-data";
import type { CountsKey, CountsResult, CountTile } from "../types/api";

interface Slot {
  key: CountsKey;
  glyph: EntityGlyph;
  name: string;
  href?: string;
}

const SLOTS: Slot[] = [
  { key: "orders", glyph: "orders", name: "Orders", href: "/data/orders" },
  { key: "refunds", glyph: "refunds", name: "Refunds", href: "/data/refunds" },
  { key: "carts", glyph: "carts", name: "Carts", href: "/data/carts" },
  { key: "products", glyph: "products", name: "Products", href: "/data/products" },
  { key: "customers", glyph: "customers", name: "Customers", href: "/data/customers" },
  { key: "cohorts", glyph: "cohorts", name: "Cohorts" },
  { key: "coupons", glyph: "coupons", name: "Coupons" },
  { key: "transactions", glyph: "transactions", name: "Transactions" },
];

export function adaptCounts(api: CountsResult): EntityCard[] {
  return SLOTS.map((s) => buildCard(s, api[s.key]));
}

function buildCard(slot: Slot, tile: CountTile): EntityCard {
  const card: EntityCard = {
    glyph: slot.glyph,
    name: slot.name,
    value: tile.count.toLocaleString(),
    delta: formatDelta(tile.delta_pct),
    deltaDir: deltaDir(tile.delta_pct),
    sub: tile.note ?? formatSub(tile),
  };
  if (slot.href) card.href = slot.href;
  return card;
}

function formatDelta(deltaPct: number | null): string {
  if (deltaPct == null) return "—";
  const arrow = deltaPct > 0 ? "↑" : deltaPct < 0 ? "↓" : "→";
  return `${arrow} ${Math.abs(deltaPct).toFixed(1)}%`;
}

function deltaDir(deltaPct: number | null): EntityCard["deltaDir"] {
  if (deltaPct == null || deltaPct === 0) return "flat";
  return deltaPct > 0 ? "up" : "down";
}

function formatSub(tile: CountTile): string {
  if (tile.prior_count == null) return "—";
  return `vs ${tile.prior_count.toLocaleString()}`;
}
