"use client";

import { useQuery } from "@tanstack/react-query";
import { fetchCounts } from "../api/data-api";
import type { DataQueryParams } from "../types/api";
import { dataKeys } from "./data-keys";

export function useDataCounts(params: DataQueryParams | null) {
  return useQuery({
    queryKey: params ? dataKeys.counts(params) : dataKeys.all,
    queryFn: () => fetchCounts(params as DataQueryParams),
    enabled: Boolean(params?.account_id),
  });
}
